import{_ as r,o as t,c as n,j as e,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"世纪四次元口袋","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/6.可升级/世纪四次元口袋.md","filePath":"4.资源分区/7.物品与装备/4.奇物/6.可升级/世纪四次元口袋.md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/6.可升级/世纪四次元口袋.md"};function _(d,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"世纪四次元口袋",tabindex:"-1"},[p("世纪四次元口袋 "),e("a",{class:"header-anchor",href:"#世纪四次元口袋","aria-label":'Permalink to "世纪四次元口袋"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌030")])])],-1),s('<h1 id="_22世纪四次元口袋" tabindex="-1">22世纪四次元口袋 <a class="header-anchor" href="#_22世纪四次元口袋" aria-label="Permalink to &quot;22世纪四次元口袋&quot;">​</a></h1><p>22世纪四次元口袋<br> 奇物 科技本质<br> 价格：500/D+500/C+1000/B+2000/A+4000【差价升级】</p><p>这是一个在22世纪非常普及的小道具，在那个时代的地球无论是谁出门在外都会带上一个款式各异的口袋。由于某种原因，提到四次元口袋人们都会不约而同的想到一只蓝色的圆脑袋卡通角色。</p><p>口袋外形默认为白色半圆形口袋，购买时你可以选择任意款式和颜色，例如格纹口袋或者牛仔帽。<br> 口袋可以直接吸附在肚子上或者其他部位，因为可以隔着衣物盔甲等物吸附，因此不会占据任何装备位，一般情况下怎么晃都不会掉下来。</p><p>根据口袋的等级，可以收纳无支线/D级及以下/C级及以下/B级及以下/A级及以下支线等级的物品，收纳空间为3m/10m/100m/1000m/10000m。<br> 口袋支线等级在B级及以上时，可以在非战斗状态下储存无助或者自愿状态下的活物，活物支线等级不能超过口袋支线等级。</p><p>【备用口袋】<br> D级及以上的口袋会赠送一个备用口袋，口袋持有者可以将备用口袋交给其他人或者放置在安全的地点，轮回者需要花十分钟把自己塞进口袋同时从备用口袋中出来，这视为旅行，持有口袋或备用口袋的轮回者进行旅行后会把持有的口袋一起带走，因此不能回到原来的地点。旅行的等级等同于口袋的支线等级。</p><p>【来自22世纪！】<br> 我是来自22世纪的保姆型机器人，请多指教！<br> 来自未来的蓝色机器人就这样这么说道，尽管不知道为什么所有人都将他当作理所当然生活在这里的居民，偶尔会把他当作狸猫。<br> “我才不是狸猫！！”</p><p>持有口袋的轮回者在影片中会获得一个命运来源的无支线/D级/C级/B级/A级背景身份，一般为普通市民等当前背景下最普通的身份，即使长得非常奇怪。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const f=r(o,[["render",_]]);export{m as __pageData,f as default};
